CustomField.formula:
AND(
 IF( Obtentor__r.Ventana_de_Desbloqueo__c = 0, false, ( ( TODAY() -  Fecha_de_Respuesta__c ) >  Obtentor__r.Ventana_de_Desbloqueo__c )
 ),
  ISPICKVAL(Estado__c, "Pendiente por IIBB"),
 OR( Obtentor__r.Id_Obtentor__c = "04", Obtentor__r.Id_Obtentor__c = "30", Obtentor__r.Id_Obtentor__c = "66" )
)
